local QBCore = exports['qb-core']:GetCoreObject()\n\nprint('^2[Factory System] Server Started^7')\n\n-- Bucket management\nlocal FactoryBuckets = {}\nlocal MaxPlayersPerBucket = Config.Factory.maxPlayers\nlocal FactoryBucketID = Config.Factory.bucket\n\n-- Initialize bucket tracking\nlocal function InitializeBucketSystem()\n    FactoryBuckets[FactoryBucketID] = {\n        playerCount = 0,\n        maxPlayers = MaxPlayersPerBucket,\n        createdAt = os.time(),\n    }\n    if Config.Debug then\n        print('^2[Factory] Bucket System initialized^7')\n        print('^2[Factory] Bucket ID: ' .. FactoryBucketID .. '^7')\n        print('^2[Factory] Max Players: ' .. MaxPlayersPerBucket .. '^7')\n    end\nend\n\n-- Player joined event\nAddEventHandler('playerJoining', function()\n    -- Ensure player starts in default bucket\n    SetPlayerRoutingBucket(source, 0)\nend)\n\n-- Player dropped event\nAddEventHandler('playerDropped', function(reason)\n    local src = source\n    if Config.Debug then\n        print('^3[Factory] Player ' .. src .. ' disconnected^7')\n    end\nend)\n\n-- Initialize on resource start\nAddEventHandler('onResourceStart', function(resourceName)\n    if GetCurrentResourceName() == resourceName then\n        InitializeBucketSystem()\n        if Config.Debug then\n            print('^2========================================^7')\n            print('^2[Factory System] Server Initialized^7')\n            print('^2========================================^7')\n        end\n    end\nend)\n\n-- Cleanup on resource stop\nAddEventHandler('onResourceStop', function(resourceName)\n    if GetCurrentResourceName() == resourceName then\n        if Config.Debug then\n            print('^3[Factory System] Server Stopped^7')\n        end\n    end\nend)", "path": "server.lua